mapper.select:
SELECT id, name, code, scope_type, tenant_id, description, enabled, created_at, updated_at
FROM provider WHERE deleted_at IS NULL
AND (#{platformAdmin} = TRUE OR scope_type = 'PLATFORM_SHARED' OR tenant_id = #{tenantId})
AND (name ILIKE CONCAT('%',#{keyword},'%') OR code ILIKE CONCAT('%',#{keyword},'%'))
AND scope_type = #{scopeType}
AND enabled = #{enabled}
ORDER BY created_at DESC, id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM provider WHERE deleted_at IS NULL
AND (#{platformAdmin} = TRUE OR scope_type = 'PLATFORM_SHARED' OR tenant_id = #{tenantId})
AND (name ILIKE CONCAT('%',#{keyword},'%') OR code ILIKE CONCAT('%',#{keyword},'%'))
AND scope_type = #{scopeType}
AND enabled = #{enabled}
